import json
from typing import Union

def convert_iam_policy_to_summary(policy_document: Union[str, dict]) -> str:
    """
    Converts an AWS IAM policy document to a human-readable summary.

    Args:
        policy_document: Either a JSON string or a dict representing an IAM policy

    Returns:
        A human-readable summary of all allowed actions
    """
    if isinstance(policy_document, str):
        policy = json.loads(policy_document)
    else:
        policy = policy_document

    summary_lines = []
    summary_lines.append("AWS IAM Policy Summary")
    summary_lines.append("=" * 40)

    if "Statement" not in policy:
        return "\n".join(summary_lines) + "\nNo statements found in policy."

    statements = policy["Statement"]
    if not isinstance(statements, list):
        statements = [statements]

    for idx, statement in enumerate(statements, 1):
        effect = statement.get("Effect", "Unknown")

        if effect != "Allow":
            continue

        summary_lines.append(f"\nStatement {idx}:")
        summary_lines.append(f"Effect: {effect}")

        actions = statement.get("Action", [])
        if isinstance(actions, str):
            actions = [actions]

        resources = statement.get("Resource", [])
        if isinstance(resources, str):
            resources = [resources]

        if actions:
            summary_lines.append("Allowed Actions:")
            for action in actions:
                summary_lines.append(f"  - {action}")

        if resources:
            summary_lines.append("Resources:")
            for resource in resources:
                summary_lines.append(f"  - {resource}")

        conditions = statement.get("Condition")
        if conditions:
            summary_lines.append("Conditions:")
            if isinstance(conditions, dict):
                for condition_type, condition_dict in conditions.items():
                    summary_lines.append(f"  {condition_type}:")
                    for key, value in condition_dict.items():
                        if isinstance(value, list):
                            for v in value:
                                summary_lines.append(f"    {key}: {v}")
                        else:
                            summary_lines.append(f"    {key}: {value}")

    return "\n".join(summary_lines)


